commands:
cat > /opt/rdf-api-project/run-with-secrets.sh << 'SCRIPT'
#!/bin/bash
export DATABASE_URL=$(gcloud secrets versions access latest --secret=database-url --project=rdf-api-project)
export NORDVPN_USERNAME=$(gcloud secrets versions access latest --secret=nordvpn-username --project=rdf-api-project)
export NORDVPN_PASSWORD=$(gcloud secrets versions access latest --secret=nordvpn-password --project=rdf-api-project)
exec "$@"
SCRIPT
